from tiktoken import get_encoding

def monitor_context_window(agent):
    encoder = get_encoding('cl100k_base')
    history_tokens = 0

    original_run = agent.run

    def tracked_run(*args, **kwargs):
        nonlocal history_tokens
        # Count tokens in agent message history
        history_str = str(agent.messages[-20:] if agent.messages else [])
        history_tokens = len(encoder.encode(history_str))

        if history_tokens > 100000:
            print(f'⚠️  CONTEXT OVERFLOW: {history_tokens} tokens')
            return {'error': 'Context window exceeded'}

        return original_run(*args, **kwargs)

    agent.run = tracked_run
    return agent

import difflib

def detect_repetition(agent):
    messages = agent.messages[-10:] if agent.messages else []
    recent_content = [m.content for m in messages[-3:]]
    older_content = [m.content for m in messages[:-3]]

    for recent in recent_content:
        for older in older_content:
            similarity = difflib.SequenceMatcher(None, recent, older).ratio()
            if similarity > 0.8:
                print(f'🔄 REPETITION DETECTED: {similarity:.1%} match')
                return True
    return False

import re

def scan_code_artifacts(code_str):
    artifacts = [
        r'\n.*?AI:', r'user:', r'assistant:', r'```python',
        r'Here is the code:', r'Let me think step by step'
    ]

    issues = []
    for pattern in artifacts:
        matches = re.findall(pattern, code_str, re.IGNORECASE)
        if matches:
            issues.append(f'Found LLM artifact: {pattern}')

    if issues:
        print('🐛 CODE CONTAMINATION:', issues)
        return False
    return True

