def rolling_context_agent(agent, max_messages=15, max_tokens=80000):
    from tiktoken import get_encoding
    encoder = get_encoding('cl100k_base')

    def run_with_context_limit(*args, **kwargs):
        # Trim history to token limit
        while len(agent.messages) > max_messages:
            agent.messages.pop(0)

        # Token-based trimming
        total_tokens = sum(len(encoder.encode(m.content)) for m in agent.messages)
        while total_tokens > max_tokens and agent.messages:
            dropped = agent.messages.pop(0)
            total_tokens -= len(encoder.encode(dropped.content))
            print(f'⏳ Trimmed {len(dropped.content)} chars')

        return agent.run(*args, **kwargs)

    agent.run = run_with_context_limit
    return agent

def compress_with_summary(agent):
    if len(agent.messages) < 10:
        return agent.run()

    # Summarize first 70% of conversation
    cutoff = len(agent.messages) // 10 * 7
    old_history = agent.messages[:cutoff]
    recent = agent.messages[cutoff:]

    summary_prompt = 'Summarize this conversation in 100 words:\n' + str(old_history)
    # Use lightweight model or cache for summary
    summary = 'Summary of prior steps: analyzed requirements, generated initial code, fixed syntax errors.'

    agent.messages = [({'role': 'system', 'content': summary})] + recent
    print('📋 Compressed history to summary')

    return agent.run()

class CheckpointAgent:
    def __init__(self, base_agent):
        self.agent = base_agent
        self.checkpoint = {'tools_used': [], 'last_output': '', 'task_state': {}}

    def run(self, *args, **kwargs):
        # Restore minimal context
        self.agent.messages = [
            {'role': 'system', 'content': f'Current state: {self.checkpoint}'}
        ]

        result = self.agent.run(*args, **kwargs)

        # Update checkpoint only
        self.checkpoint.update({
            'last_output': str(result)[:500],
            'tools_used': self.checkpoint['tools_used'][-3:]
        })

        return result

    def get_agent(self):
        return self.agent
